#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
bool flag,vis[60];
int T,n,to[60],d[60],cnt,Ans;
queue<int> q;string s,t;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}int C_N(char c){
    if(c>='a'&&c<='z')return c-'a'+1;
    if(c>='A'&&c<='Z')return 27+c-'A';
}void DFS(int u){vis[u]=1;if(!vis[to[u]])DFS(to[u]);return;}
int main(){
    T=read();
    while(T--){
        cin>>s>>t;n=s.size();
        s=" "+s,t=" "+t;cnt=0,Ans=0,flag=0;
        for(int i=1;i<=52;i++)to[i]=0,d[i]=0,vis[i]=0;
        for(int i=1;i<=n;i++){
            if(to[C_N(s[i])]&&to[C_N(s[i])]!=C_N(t[i]))flag=1;
            to[C_N(s[i])]=C_N(t[i]);
            if(!vis[C_N(t[i])])cnt++,vis[C_N(t[i])]=1;
        }if(flag){cout<<"-1\n";continue;}
        if(cnt==52){
            for(int i=1;i<=n;i++)if(s[i]!=t[i])flag=1;
            if(flag)cout<<"-1\n";else cout<<"0\n";continue;
        }for(int i=1;i<=52;i++)to[i]=0,vis[i]=0;
        for(int i=1;i<=n;i++)
            if(s[i]!=t[i]&&!to[C_N(s[i])])
                to[C_N(s[i])]=C_N(t[i]),Ans++,d[C_N(t[i])]++;
        for(int i=1;i<=52;i++)if(!d[i])q.push(i);
        while(!q.empty()){
            int u=q.front();q.pop();
            d[u]=0,vis[u]=1;if(!vis[to[u]])q.push(to[u]);
        }for(int i=1;i<=52;i++)if(!vis[i])Ans++,DFS(i);
        cout<<Ans<<"\n";
    }
    return 0;
}
